"use strict";exports.formatDate=function(e,t="YYYY-MM-DD"){if(!e)return"--";try{let r=e;"string"==typeof e&&(r=e.replace(/^(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2}:\d{2})$/,"$1T$2"),r=r.replace(/^(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2})$/,"$1T$2"));const a=new Date(r);if(isNaN(a.getTime()))return"--";const n=a.getFullYear(),d=String(a.getMonth()+1).padStart(2,"0"),c=String(a.getDate()).padStart(2,"0"),p=String(a.getHours()).padStart(2,"0"),l=String(a.getMinutes()).padStart(2,"0"),i=String(a.getSeconds()).padStart(2,"0"),s=["星期日","星期一","星期二","星期三","星期四","星期五","星期六"][a.getDay()];return t.replace("YYYY",n).replace("MM",d).replace("DD",c).replace("HH",p).replace("mm",l).replace("ss",i).replace("dddd",s)}catch(r){return console.error("日期格式化错误:",r),"--"}},exports.formatDateTime=function(e,t="YYYY-MM-DD HH:mm"){if(!e)return"--";try{let r=e;"string"==typeof e&&(r=e.replace(/^(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2}:\d{2})$/,"$1T$2"),r=r.replace(/^(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2})$/,"$1T$2"));const a=new Date(r);if(isNaN(a.getTime()))return"--";const n=a.getFullYear(),d=String(a.getMonth()+1).padStart(2,"0"),c=String(a.getDate()).padStart(2,"0"),p=String(a.getHours()).padStart(2,"0"),l=String(a.getMinutes()).padStart(2,"0"),i=String(a.getSeconds()).padStart(2,"0");return"YYYY-MM-DD HH:mm"===t?`${n}-${d}-${c} ${p}:${l}`:t.replace("YYYY",n).replace("MM",d).replace("DD",c).replace("HH",p).replace("mm",l).replace("ss",i)}catch(r){return console.error("时间格式化错误:",r),"--"}},exports.formatTime=function(e,t="YYYY-MM-DD HH:mm"){const r=function(e){if(!e)return null;if(e instanceof Date)return isNaN(e.getTime())?null:e;try{let t=e;"string"==typeof e&&(t=e.replace(/^(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2}:\d{2})$/,"$1T$2"),t=t.replace(/^(\d{4}-\d{2}-\d{2})\s(\d{2}:\d{2})$/,"$1T$2"));const r=new Date(t);return isNaN(r.getTime())?null:r}catch(t){return console.error("日期解析错误:",t,"输入:",e),null}}(e);if(!r)return"--";const a=r.getFullYear(),n=String(r.getMonth()+1).padStart(2,"0"),d=String(r.getDate()).padStart(2,"0"),c=String(r.getHours()).padStart(2,"0"),p=String(r.getMinutes()).padStart(2,"0"),l=String(r.getSeconds()).padStart(2,"0"),i=["星期日","星期一","星期二","星期三","星期四","星期五","星期六"][r.getDay()];return t.replace("YYYY",a).replace("MM",n).replace("DD",d).replace("HH",c).replace("mm",p).replace("ss",l).replace("dddd",i)};
